def test_non_manager_role_forbidden_from_viewing_employee(
    employee_token, existing_employee_id, audit_log_client
):
    before_count = audit_log_client.count_entries(
        action="view_employee",
        entity_id=existing_employee_id
    )
    response = <api_get>(
        f"/employees/{existing_employee_id}",
        headers={"Authorization": f"Bearer {employee_token}"}
    )
    assert response.status_code == 403
    body = response.json()
    assert "forbidden" in body.get("error", "").lower() or \
           "permission" in body.get("message", "").lower()
    after_count = audit_log_client.count_entries(
        action="view_employee",
        entity_id=existing_employee_id
    )
    assert after_count == before_count, "No audit record should be written"
